class LRUCache:
    """Fixed-capacity cache that evicts the least recently used key."""

    def __init__(self, capacity):
        if capacity < 1:
            raise ValueError('capacity must be at least 1')
        self.capacity = capacity
        self.data = {}
        self.order = []  # least recently used first

    def __len__(self):
        return len(self.data)

    def get(self, key):
        """Return the cached value, or -1 on a miss."""
        if key not in self.data:
            return -1
        self.order.remove(key)
        self.order.append(key)  # move to end (most recently used)
        return self.data[key]

    def put(self, key, value):
        """Insert or update a key, evicting the LRU key if full."""
        if key in self.data:
            self.data[key] = value
            self.order.remove(key)
            self.order.append(key)
            return
        if len(self.data) >= self.capacity:
            oldest = self.order.pop(0)
            del self.data[oldest]
        self.data[key] = value
        self.order.append(key)
