def wrap(text, width):
    """Greedy word-wrap: returns a list of lines, each <= width chars."""
    if width < 1:
        raise ValueError('width must be positive')
    lines = []
    line = ''
    for word in text.split():
        if len(word) > width:
            # hard-break long words into chunks
            while len(word) > width:
                chunk = word[:width]
                if line and len(line) + 1 + len(chunk) <= width:
                    line += ' ' + chunk
                else:
                    lines.append(line)
                    line = chunk
                word = word[width:]
            # add the remaining part of the long word
            if not line:
                line = word
            elif len(line) + 1 + len(word) <= width:
                line = line + ' ' + word
            else:
                lines.append(line)
                line = word
        else:
            if not line:
                line = word
            elif len(line) + 1 + len(word) <= width:
                line = line + ' ' + word
            else:
                lines.append(line)
                line = word
    if line:
        lines.append(line)
    return lines

def line_lengths(text, width):
    """Lengths of each wrapped line; handy for layout checks."""
    return [len(line) for line in wrap(text, width)]
