def tokenize(s):
    """Split a command line into tokens; double quotes group words."""
    tokens = []
    current = ''
    in_quotes = False
    for ch in s:
        if ch == '"':
            in_quotes = not in_quotes
        elif ch == ' ' and not in_quotes:
            if current:
                tokens.append(current)
            current = ''
        else:
            current += ch
    if current:
        tokens.append(current)
    return tokens

def count_tokens(s):
    """Number of tokens in the input."""
    return len(tokenize(s))
