def _adjacency(edges):
    """Undirected adjacency map, neighbor lists in edge order."""
    adj = {}
    for a, b in edges:
        adj.setdefault(a, []).append(b)
        adj.setdefault(b, []).append(a)
    return adj

def shortest_len(edges, a, b):
    """Number of edges on the shortest path a..b, or -1 if unreachable."""
    if a == b:
        return 0
    adj = _adjacency(edges)
    frontier = [(a, 0)]
    seen = {a: 0}
    while frontier:
        node, dist = frontier.pop(0)  # Use queue instead of stack
        for nxt in adj.get(node, []):
            new_dist = dist + 1
            if nxt == b:
                return new_dist
            if nxt not in seen or new_dist < seen[nxt]:
                seen[nxt] = new_dist
                frontier.append((nxt, new_dist))
    return -1

def reachable(edges, a):
    """Sorted list of every node reachable from a (including a)."""
    adj = _adjacency(edges)
    seen = {a}
    stack = [a]
    while stack:
        node = stack.pop()
        for nxt in adj.get(node, []):
            if nxt not in seen:
                seen.add(nxt)
                stack.append(nxt)
    return sorted(seen)

