def compress(xs):
    """Run-length encode xs into [value, count] pairs."""
    pairs = []
    if not xs:
        return pairs
    current = xs[0]
    count = 1
    for x in xs[1:]:
        if x == current:
            count += 1
        else:
            pairs.append([current, count])
            current = x
            count = 1
    pairs.append([current, count])  # append the last pair
    return pairs

def expand(pairs):
    """Inverse of compress: rebuild the original list."""
    out = []
    for value, count in pairs:
        if count < 0:
            raise ValueError('negative count')
        out.extend([value] * count)
    return out
```

